INSERT INTO `features` VALUES (1,'Beranda','Home page','link',NULL,'/',1,NULL,NULL,0,'none','beranda',NULL,NULL,'2026-03-10 14:12:42','2026-03-12 10:47:17'),(3,'Pameran Arsip','Archive Exhibition','dropdown',NULL,NULL,3,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-11 19:54:25'),(4,'Publikasi','Publication','dropdown',NULL,NULL,4,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-11 19:54:21'),(5,'Layanan Publik','Public Service','dropdown',NULL,NULL,5,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-11 19:54:17'),(6,'Kontak Kami','Contact Us','link',NULL,'/kontak-kami',7,'<div style=\"max-width:680px; font-family:sans-serif; color:#222;\">\r\n\r\n  <!-- INTRO -->\r\n  <p style=\"margin:0 0 20px;\">Kami siap membantu menjawab pertanyaan dan memberikan layanan terbaik untuk kebutuhan kearsipan.</p>\r\n\r\n  <!-- 3 KARTU BIRU -->\r\n  <div style=\"display:flex; gap:12px; margin-bottom:32px;\">\r\n\r\n    <div style=\"flex:1; background-color:#1a3a6b; color:#ffffff; border-radius:8px; padding:20px 12px; text-align:center;\">\r\n      <div style=\"font-size:28px; margin-bottom:8px;\">📍</div>\r\n      <div style=\"font-size:12px; opacity:0.8; margin-bottom:4px;\">Lokasi Strategis</div>\r\n      <div style=\"font-size:18px; font-weight:bold;\">Bandung</div>\r\n    </div>\r\n\r\n    <div style=\"flex:1; background-color:#1a3a6b; color:#ffffff; border-radius:8px; padding:20px 12px; text-align:center;\">\r\n      <div style=\"font-size:28px; margin-bottom:8px;\">🏢</div>\r\n      <div style=\"font-size:12px; opacity:0.8; margin-bottom:4px;\">Depot Pertama</div>\r\n      <div style=\"font-size:18px; font-weight:bold;\">Jawa Barat</div>\r\n    </div>\r\n\r\n    <div style=\"flex:1; background-color:#1a3a6b; color:#ffffff; border-radius:8px; padding:20px 12px; text-align:center;\">\r\n      <div style=\"font-size:28px; margin-bottom:8px;\">🕐</div>\r\n      <div style=\"font-size:12px; opacity:0.8; margin-bottom:4px;\">Layanan</div>\r\n      <div style=\"font-size:18px; font-weight:bold;\">5 Hari</div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <!-- ALAMAT -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 12px;\">Alamat</h3>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Alamat Lengkap</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">Jalan Ciwastra, Mekarjaya, Kecamatan Rancasari, Kota Bandung, Jawa Barat</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Kode Pos</p>\r\n  <p style=\"margin:0 0 28px; font-size:14px;\">40292</p>\r\n\r\n  <!-- TELEPON DAN EMAIL -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 12px;\">Telepon dan Email</h3>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Telepon Kantor</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">(+62) 21 7805851</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">WhatsApp</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Email</p>\r\n  <p style=\"margin:0 0 28px; font-size:14px;\">\r\n    <a href=\"mailto:depotbandung@anri.go.id\" style=\"color:#1565c0; text-decoration:none;\">depotbandung@anri.go.id</a>\r\n  </p>\r\n\r\n  <!-- MEDIA SOSIAL -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 12px;\">Media Sosial</h3>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Instagram</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Twitter</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Facebook</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Youtube</p>\r\n  <p style=\"margin:0 0 28px; font-size:14px;\">-</p>\r\n\r\n  <!-- JAM OPERASIONAL -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 6px;\">Jam Operasional</h3>\r\n  <p style=\"margin:0 0 16px; font-size:14px; color:#555;\">Waktu pelayanan Depot Arsip Berkelanjutan Bandung</p>\r\n\r\n  <table style=\"width:100%; border-collapse:separate; border-spacing:0 8px; font-size:14px;\">\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; width:50%;\">Senin</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Selasa</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Rabu</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Kamis</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Jumat</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n  </table>\r\n\r\n</div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222;\">\r\n\r\n  <!-- INTRO -->\r\n  <p style=\"margin:0 0 20px;\">We are ready to help answer questions and provide the best service for your archival needs.</p>\r\n\r\n  <!-- 3 BLUE CARDS -->\r\n  <div style=\"display:flex; gap:12px; margin-bottom:32px;\">\r\n\r\n    <div style=\"flex:1; background-color:#1a3a6b; color:#ffffff; border-radius:8px; padding:20px 12px; text-align:center;\">\r\n      <div style=\"font-size:28px; margin-bottom:8px;\">📍</div>\r\n      <div style=\"font-size:12px; opacity:0.8; margin-bottom:4px;\">Strategic Location</div>\r\n      <div style=\"font-size:18px; font-weight:bold;\">Bandung</div>\r\n    </div>\r\n\r\n    <div style=\"flex:1; background-color:#1a3a6b; color:#ffffff; border-radius:8px; padding:20px 12px; text-align:center;\">\r\n      <div style=\"font-size:28px; margin-bottom:8px;\">🏢</div>\r\n      <div style=\"font-size:12px; opacity:0.8; margin-bottom:4px;\">First Depot</div>\r\n      <div style=\"font-size:18px; font-weight:bold;\">West Java</div>\r\n    </div>\r\n\r\n    <div style=\"flex:1; background-color:#1a3a6b; color:#ffffff; border-radius:8px; padding:20px 12px; text-align:center;\">\r\n      <div style=\"font-size:28px; margin-bottom:8px;\">🕐</div>\r\n      <div style=\"font-size:12px; opacity:0.8; margin-bottom:4px;\">Services</div>\r\n      <div style=\"font-size:18px; font-weight:bold;\">5 Days</div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <!-- ADDRESS -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 12px;\">Address</h3>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Complete Address</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">Ciwastra Street, Mekarjaya, Rancasari District, Bandung City, West Java</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Postal Code</p>\r\n  <p style=\"margin:0 0 28px; font-size:14px;\">40292</p>\r\n\r\n  <!-- TELEPHONE AND EMAIL -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 12px;\">Phone and Email</h3>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Office Phone</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">(+62) 21 7805851</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">WhatsApp</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Email</p>\r\n  <p style=\"margin:0 0 28px; font-size:14px;\">\r\n    <a href=\"mailto:depotbandung@anri.go.id\" style=\"color:#1565c0; text-decoration:none;\">depotbandung@anri.go.id</a>\r\n  </p>\r\n\r\n  <!-- SOCIAL MEDIA -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 12px;\">Social Media</h3>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Instagram</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Twitter</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Facebook</p>\r\n  <p style=\"margin:0 0 16px; font-size:14px;\">-</p>\r\n\r\n  <p style=\"margin:0 0 4px; font-weight:bold; font-size:15px;\">Youtube</p>\r\n  <p style=\"margin:0 0 28px; font-size:14px;\">-</p>\r\n\r\n  <!-- OPERATING HOURS -->\r\n  <h3 style=\"font-size:18px; font-weight:bold; margin:0 0 6px;\">Operating Hours</h3>\r\n  <p style=\"margin:0 0 16px; font-size:14px; color:#555;\">Bandung Sustainable Archive Depot service times</p>\r\n\r\n  <table style=\"width:100%; border-collapse:separate; border-spacing:0 8px; font-size:14px;\">\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; width:50%;\">Monday</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Tuesday</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Wednesday</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Thursday</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n    <tr>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px;\">Friday</td>\r\n      <td style=\"background:#f5f5f5; border-radius:6px; padding:14px 16px; text-align:right;\">09.00 – 15.00 WIB</td>\r\n    </tr>\r\n  </table>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-04-28 18:50:28'),(10,'Pameran Arsip Onsite','Onsite Archives Exhibition','link',3,'/pameran-arsip/pameran-arsip-onsite',1,NULL,NULL,0,'none','onsite',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:14:56'),(11,'Pameran Arsip Virtual','Virtual Archives Exhibition','dropdown',3,NULL,2,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:15:13'),(15,'Berita',NULL,'link',4,'/publikasi/berita',1,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:12:42'),(16,'Artikel',NULL,'link',4,'/publikasi/artikel',2,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:12:42'),(17,'Galeri',NULL,'link',4,'/publikasi/galeri',3,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:12:42'),(18,'Video',NULL,'link',4,'/publikasi/video',4,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:12:42'),(19,'Layanan Arsip','Archive Services','link',5,'/layanan-publik/layanan-arsip',1,'<div style=\"width:100%; height:85vh;\">\r\n  <iframe \r\n    src=\"http://10.10.0.71:8080/\"\r\n    width=\"100%\" \r\n    height=\"100%\"\r\n    frameborder=\"0\"\r\n    style=\"border-radius:8px; border:1px solid #e2e8f0;\">\r\n  </iframe>\r\n</div>','<div style=\"width:100%; height:85vh;\">\r\n  <iframe \r\n    src=\"http://10.10.0.71:8080/\"\r\n    width=\"100%\" \r\n    height=\"100%\"\r\n    frameborder=\"0\"\r\n    style=\"border-radius:8px; border:1px solid #e2e8f0;\">\r\n  </iframe>\r\n</div>',0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-04-22 14:40:43'),(20,'Layanan Penelitian','Research Services','link',5,'/layanan-publik/layanan-penelitian',2,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-11 19:54:59'),(21,'Layanan Konsultasi','Consultation Services','link',5,'/layanan-publik/layanan-konsultasi',3,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-11 19:55:03'),(22,'Layanan Digitalisasi',NULL,'link',5,'/layanan/digitalisasi',4,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-10 14:12:42'),(23,'Layanan Restorasi','Restoration Services','link',5,'/layanan-publik/layanan-restorasi',5,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-10 14:12:42','2026-03-11 19:55:08'),(24,'Pameran Arsip Virtual 360°','360° Virtual Archives Exhibition','link',11,'/pameran-arsip-virtual/pameran-arsip-virtual-360',1,NULL,NULL,0,'none','real',NULL,NULL,'2026-03-10 14:48:28','2026-04-21 22:07:35'),(25,'Pameran Arsip Ruangan Virtual','Virtual Room Archive Exhibition','link',11,'/pameran-arsip-virtual/pameran-arsip-ruangan-virtual',2,NULL,NULL,0,'none','3d',NULL,NULL,'2026-03-10 14:51:49','2026-04-21 22:08:54'),(26,'Pameran Arsip Virtual Buku','Virtual Archives of Books Exhibition','link',11,'/pameran-arsip-virtual/pameran-arsip-virtual-buku',3,NULL,NULL,1,'none','book',NULL,NULL,'2026-03-10 15:05:20','2026-03-25 21:54:47'),(37,'Pameran Arsip Virtual SlideShow','SlideShow Virtual Archives Exhibition','link',11,'/pameran-arsip-virtual/pameran-arsip-virtual-slideshow',4,NULL,NULL,0,'none','slideshow',NULL,NULL,'2026-03-15 16:39:41','2026-03-25 21:58:34'),(40,'Profil','Profile','dropdown',NULL,NULL,2,NULL,NULL,0,'none','none',NULL,NULL,'2026-03-29 13:09:56','2026-03-29 13:09:56'),(41,'Tugas dan Fungsi','Duties and Functions','link',40,'/profil/tugas-dan-fungsi',1,NULL,NULL,0,'none','profile',NULL,NULL,'2026-03-29 13:10:50','2026-04-01 12:30:57'),(42,'Struktur Organisasi','Organizational structure','link',40,'/profil/struktur-organisasi',2,NULL,NULL,0,'none','profile',NULL,NULL,'2026-04-01 12:06:53','2026-04-01 12:31:04'),(43,'Pengelolaan','Management','dropdown',NULL,NULL,6,NULL,NULL,0,'none','none',NULL,NULL,'2026-04-22 12:36:58','2026-04-22 12:37:39'),(44,'Penyusutan Arsip','Archive Shrinkage','link',43,'/pengelolaan/penyusutan-arsip',1,'<div style=\"max-width:680px; text-align:justify;\">\r\n\r\n<div style=\"display:flex; gap:2%; margin:0 0 20px 0;\">\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Foto 1</div>\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Foto 2</div>\r\n</div>\r\n\r\n<p>Penyusutan arsip adalah proses pengurangan jumlah arsip melalui pemindahan arsip inaktif dari unit pengolah ke unit kearsipan, pemusnahan arsip yang tidak memiliki nilai guna, dan penyerahan arsip statis kepada lembaga kearsipan. Penyusutan arsip mencakup kegiatan-kegiatan berikut:</p>\r\n\r\n<!-- NOMOR 1 -->\r\n<p style=\"margin-top:24px; margin-bottom:6px;\"><strong>1. Pemindahan arsip inaktif</strong> dari unit pengolah ke unit kearsipan, dilaksanakan melalui tahapan berikut:</p>\r\n<p style=\"margin:0 0 2px 20px;\">a. Pemilahan arsip inaktif;</p>\r\n<p style=\"margin:0 0 2px 20px;\">b. Penataan arsip inaktif; dan</p>\r\n<p style=\"margin:0 0 0 20px;\">c. Pembuatan daftar arsip inaktif.</p>\r\n\r\n<!-- NOMOR 2 -->\r\n<p style=\"margin-top:24px; margin-bottom:6px;\"><strong>2. Pemusnahan arsip</strong> yang telah habis masa retensinya dan tidak memiliki nilai guna, dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan, melalui tahapan berikut:</p>\r\n<p style=\"margin:0 0 2px 20px;\">a. Pembentukan Panitia Penilai Arsip;</p>\r\n<p style=\"margin:0 0 2px 20px;\">b. Pemilahan arsip;</p>\r\n<p style=\"margin:0 0 2px 20px;\">c. Pembuatan Daftar Arsip Usul Musnah;</p>\r\n<p style=\"margin:0 0 2px 20px;\">d. Penilaian arsip;</p>\r\n<p style=\"margin:0 0 2px 20px;\">e. Permohonan persetujuan;</p>\r\n<p style=\"margin:0 0 2px 20px;\">f. Penetapan arsip yang akan dimusnahkan; dan</p>\r\n<p style=\"margin:0 0 0 20px;\">g. Pelaksanaan pemusnahan arsip.</p>\r\n\r\n<!-- NOMOR 3 -->\r\n<p style=\"margin-top:24px; margin-bottom:6px;\"><strong>3. Penyerahan arsip statis</strong> oleh pencipta arsip kepada lembaga kearsipan, dilaksanakan melalui tahapan berikut:</p>\r\n<p style=\"margin:0 0 2px 20px;\">a. Pemilahan dan pembuatan Daftar Arsip Usul Serah;</p>\r\n<p style=\"margin:0 0 2px 20px;\">b. Penilaian;</p>\r\n<p style=\"margin:0 0 2px 20px;\">c. Pemberitahuan penyerahan arsip statis;</p>\r\n<p style=\"margin:0 0 2px 20px;\">d. Verifikasi dan persetujuan;</p>\r\n<p style=\"margin:0 0 2px 20px;\">e. Penetapan arsip yang akan diserahkan; dan</p>\r\n<p style=\"margin:0 0 0 20px;\">f. Pelaksanaan penyerahan arsip statis.</p>\r\n\r\n</div>','<div style=\"max-width:680px; text-align:justify;\">\r\n\r\n<div style=\"display:flex; gap:2%; margin:0 0 20px 0;\">\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Photo 1</div>\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Photo 2</div>\r\n</div>\r\n\r\n<p>Archive shrinkage is the process of reducing the number of archives through transferring inactive archives from processing units to archival units, destroying archives that have no use value, and handing over static archives to archival institutions. Archive depreciation includes the following activities:</p>\r\n\r\n<!-- NUMBER 1 -->\r\n<p style=\"margin-top:24px; margin-bottom:6px;\"><strong>1. The transfer of inactive archives</strong>from the processing unit to the archives unit, is carried out through the following stages:</p>\r\n<p style=\"margin:0 0 2px 20px;\">a. Inactive archive sorting;</p>\r\n<p style=\"margin:0 0 2px 20px;\">b. Inactive archive setup; and</p>\r\n<p style=\"margin:0 0 0 20px;\">c. Creation of a list of inactive archives.</p>\r\n\r\n<!-- NUMBER 2 -->\r\n<p style=\"margin-top:24px; margin-bottom:6px;\"><strong>2. Destruction of archives whose retention period has expired and have no use value is carried out in accordance with statutory provisions, through the following stages:</p>\r\n<p style=\"margin:0 0 2px 20px;\">a. Establishment of an Archives Assessment Committee;</p>\r\n<p style=\"margin:0 0 2px 20px;\">b. Archive sorting;</p>\r\n<p style=\"margin:0 0 2px 20px;\">c. Making a List of Archives of Proposed Destruction;</p>\r\n<p style=\"margin:0 0 2px 20px;\">d. Archive assessment;</p>\r\n<p style=\"margin:0 0 2px 20px;\">e. Request for approval;</p>\r\n<p style=\"margin:0 0 2px 20px;\">f. Determination of archives to be destroyed; and</p>\r\n<p style=\"margin:0 0 0 20px;\">g. Execution of archive destruction.</p>\r\n\r\n<!-- NUMBER 3 -->\r\n<p style=\"margin-top:24px; margin-bottom:6px;\"><strong>3. Submission of static archives</strong>by archive creators to archival institutions, is carried out through the following stages:</p>\r\n<p style=\"margin:0 0 2px 20px;\">a. Sorting and creating a List of Handover Proposal Archives;</p>\r\n<p style=\"margin:0 0 2px 20px;\">b. Assessment;</p>\r\n<p style=\"margin:0 0 2px 20px;\">c. Static archive submission notice;</p>\r\n<p style=\"margin:0 0 2px 20px;\">d. Verification and approval;</p>\r\n<p style=\"margin:0 0 2px 20px;\">e. Determination of archives to be submitted; and</p>\r\n<p style=\"margin:0 0 0 20px;\">f. Implementation of static archive submission.</p>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-04-22 12:38:39','2026-04-26 18:42:24'),(45,'Penyimpanan Arsip','Archive Storage','link',43,'/pengelolaan/penyimpanan-arsip',2,'<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Penyimpanan arsip adalah penempatan dan penataan arsip secara sistematis sesuai dengan kaidah dan aturan kearsipan guna menjamin keamanan fisik dan integritas arsip. Dalam pengelolaan arsip statis, penyimpanan dilakukan untuk:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Menjaga integritas dan autentisitas arsip</li>\r\n    <li style=\"margin-bottom:6px;\">Melindungi arsip dari kerusakan fisik dan lingkungan</li>\r\n    <li style=\"margin-bottom:6px;\">Memudahkan proses temu kembali arsip</li>\r\n    <li style=\"margin-bottom:6px;\">Mendukung layanan akses kepada masyarakat</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Prinsip Penyimpanan Arsip Statis</h3>\r\n  <p>Penyimpanan arsip statis dilaksanakan berdasarkan prinsip-prinsip berikut:</p>\r\n\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Integritas</strong><br>\r\n      Arsip disimpan tanpa mengubah struktur asli dan konteks penciptaannya.\r\n    </li>\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Autentisitas</strong><br>\r\n      Arsip dijaga keasliannya dan bebas dari manipulasi.\r\n    </li>\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Keamanan</strong><br>\r\n      Arsip dilindungi dari kehilangan, pencurian, dan bencana.\r\n    </li>\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Aksesibilitas</strong><br>\r\n      Arsip ditata sedemikian rupa agar dapat ditemukan kembali dengan cepat dan tepat.\r\n    </li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Sistem Penyimpanan Arsip</h3>\r\n\r\n  <!-- KARTU SISTEM -->\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Sistem Nomor (Klasifikasi Arsip)</strong><br>\r\n    <span style=\"font-size:14px;\">Arsip disimpan berdasarkan kode atau nomor klasifikasi sesuai jenis kegiatan atau masalah.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Sistem Subjek</strong><br>\r\n    <span style=\"font-size:14px;\">Arsip dikelompokkan berdasarkan topik utama atau isi dokumen, sehingga memudahkan pencarian berdasarkan subjek tertentu.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Sistem Abjad</strong><br>\r\n    <span style=\"font-size:14px;\">Arsip disusun secara alfabetis (A–Z), biasanya berdasarkan nama individu, lembaga, atau organisasi.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Sistem Tanggal (Kronologis)</strong><br>\r\n    <span style=\"font-size:14px;\">Arsip disimpan berdasarkan tanggal pembuatan atau penerimaan dokumen, sehingga memudahkan temu kembali arsip berdasarkan waktu.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:24px;\">\r\n    <strong>Sistem Wilayah</strong><br>\r\n    <span style=\"font-size:14px;\">Arsip dikelompokkan berdasarkan wilayah atau asal geografis dokumen, umumnya digunakan oleh lembaga yang mengelola dokumen dari berbagai daerah.</span>\r\n  </div>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Sarana dan Prasarana Penyimpanan</h3>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n    <li style=\"margin-bottom:6px;\">Pengatur Suhu dan Kelembaban</li>\r\n    <li style=\"margin-bottom:6px;\">Kotak Arsip Bebas Asam</li>\r\n    <li style=\"margin-bottom:6px;\">Rak Arsip Khusus</li>\r\n    <li style=\"margin-bottom:6px;\">Sistem Keamanan (CCTV, kontrol akses ruangan, dan sistem registrasi keluar-masuk arsip)</li>\r\n  </ul>\r\n\r\n  <!-- FOTO 4 KOTAK -->\r\n  <div style=\"display:flex; gap:2%; margin-bottom:10px;\">\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Foto 1</div>\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Foto 2</div>\r\n  </div>\r\n  <div style=\"display:flex; gap:2%; margin-bottom:24px;\">\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Foto 3</div>\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Foto 4</div>\r\n  </div>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Jenis Ruang Penyimpanan</h3>\r\n  <p>Dalam pengelolaan arsip statis, ruang penyimpanan dibagi menjadi:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Ruang Penyimpanan Arsip Statis</li>\r\n    <li style=\"margin-bottom:6px;\">Ruang Arsip Media Khusus</li>\r\n    <li style=\"margin-bottom:6px;\">Ruang Arsip Vital</li>\r\n    <li style=\"margin-bottom:6px;\">Ruang Preservasi dan Restorasi</li>\r\n    <li style=\"margin-bottom:6px;\">Ruang Karantina Arsip</li>\r\n  </ul>\r\n\r\n</div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Archive storage is the systematic placement and arrangement of archives in accordance with archival rules and regulations to ensure physical security and integrity of archives. In static archive management, storage is carried out for:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Maintaining the integrity and authenticity of archives</li>\r\n    <li style=\"margin-bottom:6px;\">Protect archives from physical and environmental damage</li>\r\n    <li style=\"margin-bottom:6px;\">Easy the archive retrieval process</li>\r\n    <li style=\"margin-bottom:6px;\">Supporting access services to the community</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Static Archive Storage Principles</h3>\r\n  <p>Static archive storage is implemented based on the following principles:</p>\r\n\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Integrity</strong><br>\r\n      Archives are stored without changing the original structure and context of their creation.\r\n    </li>\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Authenticity</strong><br>\r\n      Archives are kept authentic and free from manipulation.\r\n    </li>\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Security</strong><br>\r\n      Archives are protected from loss, theft and disaster.\r\n    </li>\r\n    <li style=\"margin-bottom:10px;\">\r\n      <strong>Accessibility</strong><br>\r\n      Archives are arranged in such a way that they can be found quickly and precisely.\r\n    </li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Archive Storage System</h3>\r\n\r\n  <!-- SYSTEM CARD -->\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Number System (Archive Classification)</strong><br>\r\n    <span style=\"font-size:14px;\">Archive files are stored based on classification codes or numbers according to the type of activity or problem.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Subject System</strong><br>\r\n    <span style=\"font-size:14px;\">Archives are grouped by main topic or document content, making it easier to search by specific subject.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Alphabet System</strong><br>\r\n    <span style=\"font-size:14px;\">Archive files are arranged alphabetically (A–Z), usually by name of individual, institution or organization.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:10px;\">\r\n    <strong>Date System (Chronological)</strong><br>\r\n    <span style=\"font-size:14px;\">Archives are stored based on the date the document was created or received, making it easier to retrieve archives based on time.</span>\r\n  </div>\r\n\r\n  <div style=\"border:1px solid #e0e0e0; border-radius:6px; padding:14px 16px; margin-bottom:24px;\">\r\n    <strong>Region System</strong><br>\r\n    <span style=\"font-size:14px;\">Archives are grouped by region or geographic origin of documents, generally used by institutions that manage documents from various regions.</span>\r\n  </div>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Storage Facilities and Infrastructure</h3>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n    <li style=\"margin-bottom:6px;\">Temperature and Humidity Control</li>\r\n    <li style=\"margin-bottom:6px;\">Acid-Free Filing Box</li>\r\n    <li style=\"margin-bottom:6px;\">Custom Archive Shelf</li>\r\n    <li style=\"margin-bottom:6px;\">Security System (CCTV, room access control, and archive entry and exit registration system)</li>\r\n  </ul>\r\n\r\n  <!-- PHOTO 4 BOXES -->\r\n  <div style=\"display:flex; gap:2%; margin-bottom:10px;\">\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Photo 1</div>\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Photo 2</div>\r\n  </div>\r\n  <div style=\"display:flex; gap:2%; margin-bottom:24px;\">\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Photo 3</div>\r\n    <div style=\"width:48%; height:180px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Photo 4</div>\r\n  </div>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Storage Space Type</h3>\r\n  <p>In static archive management, storage space is divided into:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Static Archive Storage Space</li>\r\n    <li style=\"margin-bottom:6px;\">Dedicated Media Archive Room</li>\r\n    <li style=\"margin-bottom:6px;\">Vital Archives Room</li>\r\n    <li style=\"margin-bottom:6px;\">Preservation and Restoration Space</li>\r\n    <li style=\"margin-bottom:6px;\">Archive Quarantine Room</li>\r\n  </ul>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-04-22 12:43:44','2026-04-28 19:11:02'),(46,'Preservasi Arsip','Archive Preservation','link',43,'/pengelolaan/preservasi-arsip',2,'<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Preservasi arsip merupakan bagian dari pengolahan arsip statis, yaitu proses pengendalian arsip statis secara efisien, efektif, dan sistematis, meliputi akuisisi, pengolahan, preservasi, pemanfaatan, optimasi, dan kegiatan lainnya dalam organisasi pemerintah maupun swasta. Terdapat dua metode yang digunakan dalam preservasi arsip, yaitu:</p>\r\n\r\n  <p><strong>Preservasi Preventif</strong>, yaitu tindakan-tindakan untuk mencegah kerusakan arsip atau dokumen dari faktor eksternal maupun internal.</p>\r\n\r\n  <p><strong>Preservasi Kuratif</strong>, yaitu tindakan untuk merawat dan memperbaiki arsip atau dokumen dengan tetap memperhatikan keutuhan informasi yang terkandung di dalamnya.</p>\r\n\r\n  <!-- FOTO 2 KOLOM -->\r\n  <div style=\"display:flex; gap:2%; margin:24px 0;\">\r\n    <div style=\"width:48%; height:200px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Foto 1</div>\r\n    <div style=\"width:48%; height:200px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Foto 2</div>\r\n  </div>\r\n\r\n  <p>Restorasi arsip adalah upaya penyelamatan arsip yang rusak. Proses restorasi dilakukan semaksimal mungkin untuk mengembalikan arsip ke bentuk aslinya, sehingga informasi atau data yang terkandung di dalamnya dapat diselamatkan dan digunakan kembali untuk kepentingan instansi atau perusahaan.</p>\r\n\r\n  <p>Dalam kondisi tertentu, restorasi arsip juga mencakup penambahan bahan baru guna mendapatkan hasil optimal dan mengembalikan kondisi arsip seperti sebelum rusak. Dengan demikian, restorasi arsip dapat didefinisikan sebagai langkah atau metode untuk memperbaiki arsip atau dokumen yang rusak.</p>\r\n\r\n  <p>Persyaratan untuk melakukan restorasi arsip antara lain: arsip yang dapat diperbaiki adalah arsip kertas yang rusak akibat bencana alam seperti banjir, gempa bumi, atau tanah longsor. Tidak semua dokumen dapat dipulihkan; arsip yang umumnya dapat diperbaiki adalah yang rusak atau hilang akibat bencana alam. Contohnya antara lain Kartu Keluarga, ijazah, akta nikah, KTP, dan dokumen keluarga penting lainnya.</p>\r\n\r\n  <p>Bagi perusahaan, pada dasarnya semua jenis arsip dapat dipulihkan, kecuali arsip vital perusahaan yang menurut Pasal 1 Ayat 4 Undang-Undang Nomor 43 Tahun 2009 tentang Kearsipan tidak dapat diperbarui atau digantikan apabila rusak atau hilang. Arsip yang akan dipulihkan juga harus memenuhi kriteria tingkat kerusakan, yaitu ringan, sedang, atau berat.</p>\r\n\r\n  <p>Beberapa jenis arsip yang tidak dapat dipulihkan dan dikembalikan kepada pengguna antara lain:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Tinta arsip telah memudar.</li>\r\n    <li style=\"margin-bottom:6px;\">Tulisan atau informasi pada arsip telah terlepas dan tidak terbaca.</li>\r\n    <li style=\"margin-bottom:6px;\">Fisik arsip telah hancur.</li>\r\n  </ul>\r\n\r\n  <p>Jika arsip tidak termasuk dalam kategori tersebut, proses restorasi dapat dilanjutkan. Bagi perusahaan, terdapat biaya tambahan yang dikenakan.</p>\r\n\r\n  <p>Beberapa metode restorasi arsip yang digunakan antara lain:</p>\r\n  <ol style=\"padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:10px;\"><strong>Pembersihan arsip</strong>, yaitu proses menghilangkan kotoran, jamur, dan faktor lain yang dapat merusak arsip. Untuk menghilangkan noda membandel seperti cat dan minyak yang meninggalkan bekas pada kertas, digunakan larutan benzena.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Deasidifikasi</strong>, yaitu proses menetralkan kandungan asam yang merusak kertas dengan menambahkan buffer untuk melindungi kertas dari asam eksternal. Metode ini hanya mengurangi dampak asam, tidak menguatkan kertas yang rapuh.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Patching dan splicing</strong>, yaitu tindakan untuk menutup lubang atau bagian yang hilang dan menyambung kembali arsip yang telah robek akibat berbagai faktor kerusakan.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Laminasi arsip</strong>, yaitu proses melapisi dokumen di antara dua bahan penguat. Laminasi umumnya diterapkan pada arsip yang sudah sangat rapuh atau rusak berat.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Enkapsulasi</strong>, yaitu teknik melindungi arsip dengan melapisinya menggunakan plastik poliester dan perekat tambahan (double tape) untuk mencegah kerusakan fisik lebih lanjut.</li>\r\n  </ol>\r\n\r\n  <p>Selain metode-metode tersebut, terdapat pula upaya restorasi yang diterapkan pada arsip digital. Restorasi arsip digital dilakukan untuk memperbaiki file yang rusak, memulihkan data yang terhapus atau korup, serta memastikan informasi tetap dapat diakses dan digunakan dalam jangka panjang. Namun, proses restorasi arsip digital memerlukan kompetensi teknis yang memadai, penggunaan perangkat lunak dan perangkat keras khusus, serta prosedur penanganan yang cermat untuk menjaga autentisitas, integritas, dan keamanan data.</p>\r\n\r\n</div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Archive preservation is part of static archive processing, namely the process of controlling static archives efficiently, effectively and systematically, including acquisition, processing, preservation, utilization, optimization and other activities in government and private organizations. There are two methods used in archival preservation, namely:</p>\r\n\r\n  <p><strong>Preventive Preservation</strong>, namely actions to prevent damage to archives or documents from external or internal factors.</p>\r\n\r\n  <p><strong>Curative Preservation</strong>, namely actions to maintain and repair archives or documents while still paying attention to the integrity of the information contained therein.</p>\r\n\r\n  <!-- 2 COLUMN PHOTO -->\r\n  <div style=\"display:flex; gap:2%; margin:24px 0;\">\r\n    <div style=\"width:48%; height:200px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Photo 1</div>\r\n    <div style=\"width:48%; height:200px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888; font-size:13px;\">Photo 2</div>\r\n  </div>\r\n\r\n  <p>Archive restoration is an effort to save damaged archives. The restoration process is carried out as much as possible to return the archive to its original form, so that the information or data contained therein can be saved and reused for the benefit of the agency or company.</p>\r\n\r\n  <p>Under certain conditions, archive restoration also includes the addition of new materials to obtain optimal results and restore the archive to the condition it was in before it was damaged. Thus, archive restoration can be defined as a step or method to repair damaged archives or documents.</p>\r\n\r\n  <p>Requirements for archival restoration include: records that can be repaired are paper records damaged by natural disasters such as floods, earthquakes or landslides. Not all documents can be recovered; Archives that generally can be repaired are those that are damaged or lost due to natural disasters. Examples include Family Cards, diplomas, marriage certificates, KTPs, and other important family documents.</p>\r\n\r\n  <p>For companies, basically all types of records can be recovered, except vital company records which according to Article 1 Paragraph 4 of Law Number 43 of 2009 concerning Archives cannot be renewed or replaced if they are damaged or lost. Archives to be restored must also meet the criteria for the level of damage, namely light, medium or heavy.</p>\r\n\r\n  <p>Some types of archives that cannot be recovered and returned to the user include:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Archive ink has faded.</li>\r\n    <li style=\"margin-bottom:6px;\">The writing or information in the archive has been removed and cannot be read.</li>\r\n    <li style=\"margin-bottom:6px;\">The physical archive has been destroyed.</li>\r\n  </ul>\r\n\r\n  <p>If the archive does not fall into this category, the restoration process can continue. For companies, there are additional fees charged.</p>\r\n\r\n  <p>Several archive restoration methods used include:</p>\r\n  <ol style=\"padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:10px;\"><strong>Archive cleaning</strong>, namely the process of removing dirt, mold, and other factors that can damage archives. To remove stubborn stains such as paint and oil that leave marks on paper, a benzene solution is used.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Deacidification</strong>, which is the process of neutralizing acid content that damages paper by adding a buffer to protect the paper from external acids. This method only reduces the impact of the acid, does not strengthen the brittle paper.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Patching and splicing</strong>, namely actions to cover holes or missing parts and reconnect archives that have been torn due to various damage factors.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Archive lamination</strong>, which is the process of layering documents between two reinforcing materials. Lamination is generally applied to archives that are very fragile or heavily damaged.</li>\r\n    <li style=\"margin-bottom:10px;\"><strong>Encapsulation</strong>, which is a technique of protecting archives by covering them with polyester plastic and additional adhesive (double tape) to prevent further physical damage.</li>\r\n  </ol>\r\n\r\n  <p>Apart from these methods, there are also restoration efforts applied to digital archives. Digital archive restoration is carried out to repair damaged files, recover deleted or corrupt data, and ensure that information remains accessible and usable in the long term. However, the digital archive restoration process requires sufficient technical competence, the use of special software and hardware, and careful handling procedures to maintain the authenticity, integrity and security of the data.</p>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-04-22 12:43:51','2026-04-28 19:17:49'),(47,'Pengolahan Arsip','Archive Processing','link',43,'/pengelolaan/pengolahan-arsip',4,'<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Pengolahan arsip statis adalah proses sistematis dalam mengatur, mendeskripsikan, dan menyajikan arsip agar mudah diakses dan digunakan oleh pengguna.</p>\r\n\r\n  <p><strong>Tahapan pengolahan meliputi:</strong></p>\r\n  <ol style=\"padding-left:20px; margin-bottom:24px;\">\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Persiapan dan Identifikasi</strong><br>\r\n      Melakukan administrasi, membentuk tim, serta mengidentifikasi kondisi fisik, jumlah, dan jenis arsip sebagai dasar perencanaan kerja.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Penyusunan Rencana dan Skema</strong><br>\r\n      Menyusun rencana teknis dan skema pengelompokan arsip berdasarkan prinsip provenance (asal pencipta arsip) dan original order.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Pengorganisasian dan Deskripsi</strong><br>\r\n      Arsip direkonstruksi, dideskripsikan, diberi nomor sementara, dan disimpan dalam media penyimpanan sesuai standar kearsipan.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Entri Data dan Pengelompokan</strong><br>\r\n      Data arsip dimasukkan ke dalam sistem, dikelompokkan berdasarkan fungsi dan struktur organisasi, kemudian diberi nomor definitif.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Pelabelan dan Penataan Fisik</strong><br>\r\n      Arsip dan kotak penyimpanan diberi label resmi dan ditata secara sistematis di rak atau lemari penyimpanan.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Penyusunan dan Pengesahan Daftar Arsip Statis</strong><br>\r\n      Daftar arsip statis disusun dan melalui tahapan koreksi, sampling, verifikasi, validasi, serta pengesahan akhir.\r\n    </li>\r\n  </ol>\r\n\r\n  <!-- GAMBAR FLOWCHART LANGSUNG TAMPIL -->\r\n  <div style=\"border-radius:10px; overflow:hidden; margin-bottom:0;\">\r\n    <img src=\"https://lh3.googleusercontent.com/d/1EJm-neV_d5JZhLVcdXR7paCW3U43cFZU\"\r\n      style=\"width:100%; display:block;\"\r\n      alt=\"Pengolahan Arsip Statis\">\r\n  </div>\r\n\r\n  <!-- KOTAK MEKANISME LAYANAN - PUTIH TIMBUL -->\r\n  <div style=\"border:1px solid #e0e0e0; border-top:none; border-radius:0 0 10px 10px; padding:28px 24px; text-align:center; background:#ffffff; box-shadow:0 6px 16px rgba(0,0,0,0.12); margin-bottom:40px;\">\r\n    <p style=\"color:#222; font-size:18px; font-weight:bold; margin:0 0 20px;\">Mekanisme Layanan</p>\r\n    <a href=\"https://drive.google.com/file/d/1UcV8SGfT5_66ND9EZI_0Nsc97x1M896p/view?usp=sharing\" target=\"_blank\"\r\n      style=\"background-color:#1a3a6b; color:#ffffff; padding:13px 48px; border-radius:30px; font-size:15px; font-weight:bold; text-decoration:none; display:inline-flex; align-items:center; gap:8px; box-shadow:0 4px 10px rgba(26,58,107,0.4);\">\r\n      <span>⬇</span> Unduh\r\n    </a>\r\n  </div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Static archive processing is a systematic process of organizing, describing and presenting archives so that they are easy to access and use by users.</p>\r\n\r\n  <p><strong>The processing stages include:</strong></p>\r\n  <ol style=\"padding-left:20px; margin-bottom:24px;\">\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Preparation and Identification</strong><br>\r\n      Carry out administration, form a team, and identify the physical condition, number and type of archives as a basis for work planning.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Preparation of Plans and Schemes</strong><br>\r\n      Develop technical plans and archive grouping schemes based on the principles of provenance (origin of the archive creator) and original order.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Organization and Description</strong><br>\r\n      Archives are reconstructed, described, given temporary numbers, and stored in storage media according to archival standards.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Data Entry and Grouping</strong><br>\r\n      Archive data is entered into the system, grouped based on function and organizational structure, then given a definitive number.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Labeling and Physical Arrangement</strong><br>\r\n      Archives and storage boxes are officially labeled and arranged systematically on shelves or storage cabinets.\r\n    </li>\r\n    <li style=\"margin-bottom:12px;\">\r\n      <strong>Preparation and Validation of Static Archives List</strong><br>\r\n      A list of static archives is compiled and goes through the stages of correction, sampling, verification, validation and final validation.\r\n    </li>\r\n  </ol>\r\n\r\n  <!-- FLOWCHART IMAGE SHOULD IMMEDIATELY -->\r\n  <div style=\"border-radius:10px; overflow:hidden; margin-bottom:0;\">\r\n    <img src=\"https://lh3.googleusercontent.com/d/1EJm-neV_d5JZhLVcdXR7paCW3U43cFZU\"\r\n      style=\"width:100%; display:block;\"\r\n      alt=\"Static Archive Processing\">\r\n  </div>\r\n\r\n  <!-- SERVICE MECHANISM BOX - WHITE embossed -->\r\n  <div style=\"border:1px solid #e0e0e0; border-top:none; border-radius:0 0 10px 10px; padding:28px 24px; text-align:center; background:#ffffff; box-shadow:0 6px 16px rgba(0,0,0,0.12); margin-bottom:40px;\">\r\n    <p style=\"color:#222; font-size:18px; font-weight:bold; margin:0 0 20px;\">Service Mechanism</p>\r\n    <a href=\"https://drive.google.com/file/d/1UcV8SGfT5_66ND9EZI_0Nsc97x1M896p/view?usp=sharing\" target=\"_blank\"\r\n      style=\"background-color:#1a3a6b; color:#ffffff; padding:13px 48px; border-radius:30px; font-size:15px; font-weight:bold; text-decoration:none; display:inline-flex; align-items:center; gap:8px; box-shadow:0 4px 10px rgba(26,58,107,0.4);\">\r\n      <span>⬇</span> Download\r\n    </a>\r\n  </div>',0,'none','none',NULL,NULL,'2026-04-22 12:45:12','2026-04-28 21:36:46'),(48,'Pemanfaatan Arsip','Utilization of Archives','link',43,'/pengelolaan/pemanfaatan-arsip',5,'<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Akses dan pemanfaatan arsip mengacu pada ketersediaan dan penggunaan arsip, baik dinamis maupun statis, berdasarkan kewenangan hukum yang berlaku untuk kepentingan administratif, penelitian, pendidikan, bukti hukum, dan kepentingan publik lainnya.</p>\r\n\r\n  <!-- KOTAK KUTIPAN -->\r\n  <div style=\"background-color:#4a4a4a; color:#ffffff; border-radius:6px; padding:16px 20px; margin:20px 0; font-style:italic; font-size:14px; line-height:1.8;\">\r\n    Berdasarkan Undang-Undang Nomor 43 Tahun 2009 tentang Kearsipan, arsip statis pada prinsipnya terbuka untuk umum, kecuali arsip yang dinyatakan tertutup berdasarkan ketentuan peraturan perundang-undangan.\r\n  </div>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Akses Arsip</h3>\r\n  <p>Ketersediaan arsip yang dapat digunakan oleh pengguna, didukung oleh:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">Daftar arsip</li>\r\n    <li style=\"margin-bottom:6px;\">Inventaris arsip</li>\r\n    <li style=\"margin-bottom:6px;\">Panduan arsip</li>\r\n    <li style=\"margin-bottom:6px;\">Sistem informasi kearsipan</li>\r\n    <li style=\"margin-bottom:6px;\">Basis data digital</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Jenis Akses</h3>\r\n\r\n  <p><strong>1. Akses Langsung</strong><br>\r\n  Pengguna datang langsung ke ruang layanan arsip (ruang baca) untuk melakukan penelitian atau penelusuran arsip.</p>\r\n\r\n  <p style=\"margin-top:12px;\"><strong>2. Akses Tidak Langsung</strong><br>\r\n  Pengguna mengakses arsip melalui:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n    <li style=\"margin-bottom:6px;\">Sistem informasi kearsipan</li>\r\n    <li style=\"margin-bottom:6px;\">Email resmi kelembagaan</li>\r\n    <li style=\"margin-bottom:6px;\">Surat permohonan layanan</li>\r\n    <li style=\"margin-bottom:6px;\">Portal arsip digital</li>\r\n  </ul>\r\n\r\n  <p style=\"text-align:left;\">\r\n    <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:11px 24px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n      Mekanisme Layanan\r\n    </a>\r\n  </p>\r\n\r\n</div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Access and utilization of archives refers to the availability and use of archives, both dynamic and static, based on applicable legal authority for administrative purposes, research, education, legal evidence and other public interests.</p>\r\n\r\n  <!-- QUOTE BOX -->\r\n  <div style=\"background-color:#4a4a4a; color:#ffffff; border-radius:6px; padding:16px 20px; margin:20px 0; font-style:italic; font-size:14px; line-height:1.8;\">\r\n    Based on Law Number 43 of 2009 concerning Archives, static archives are in principle open to the public, except for archives that are declared closed based on the provisions of statutory regulations.\r\n  </div>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Archive Access</h3>\r\n  <p>Availability of archives that can be used by users, supported by:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:16px;\">\r\n    <li style=\"margin-bottom:6px;\">List of archives</li>\r\n    <li style=\"margin-bottom:6px;\">Archive inventory</li>\r\n    <li style=\"margin-bottom:6px;\">Archive guide</li>\r\n    <li style=\"margin-bottom:6px;\">Archive information system</li>\r\n    <li style=\"margin-bottom:6px;\">Digital database</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Access Type</h3>\r\n\r\n  <p><strong>1. Direct Access</strong><br>\r\n  Users come directly to the archive service room (reading room) to carry out research or search archives.</p>\r\n\r\n  <p style=\"margin-top:12px;\"><strong>2. Indirect Access</strong><br>\r\n  Users access the archive via:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n    <li style=\"margin-bottom:6px;\">Archive information system</li>\r\n    <li style=\"margin-bottom:6px;\">Official institutional email</li>\r\n    <li style=\"margin-bottom:6px;\">Service request letter</li>\r\n    <li style=\"margin-bottom:6px;\">Digital archive portal</li>\r\n  </ul>\r\n\r\n  <p style=\"text-align:left;\">\r\n    <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:11px 24px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n      Service Mechanism\r\n    </a>\r\n  </p>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-04-22 12:45:55','2026-04-28 20:01:47'),(49,'Penjangkauan Arsip','Archives Outreach','link',43,'/pengelolaan/penjangkauan-arsip',6,'<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Penjangkauan arsip adalah upaya strategis lembaga kearsipan untuk memperkenalkan, mempromosikan, dan mendekatkan arsip kepada masyarakat luas.</p>\r\n\r\n  <!-- KOTAK KUTIPAN -->\r\n  <div style=\"background-color:#4a4a4a; color:#ffffff; border-radius:6px; padding:16px 20px; margin:20px 0; font-style:italic; font-size:14px; line-height:1.8;\">\r\n    Berdasarkan Undang-Undang Nomor 43 Tahun 2009 tentang Kearsipan, arsip merupakan memori kolektif bangsa, sumber informasi, dan bahan pertanggungjawaban nasional. Oleh karena itu, lembaga kearsipan tidak hanya menyimpan arsip, tetapi juga aktif menyebarluaskan informasi kearsipan kepada masyarakat.\r\n  </div>\r\n\r\n  <p>Penjangkauan arsip dilaksanakan untuk:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:20px;\">\r\n    <li style=\"margin-bottom:6px;\">Meningkatkan kesadaran masyarakat tentang pentingnya arsip</li>\r\n    <li style=\"margin-bottom:6px;\">Memperluas penggunaan arsip sebagai sumber sejarah</li>\r\n    <li style=\"margin-bottom:6px;\">Mendukung pendidikan dan penelitian</li>\r\n    <li style=\"margin-bottom:6px;\">Membangun citra arsip sebagai sumber informasi yang terbuka dan terpercaya</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Tujuan Penjangkauan Arsip</h3>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:20px;\">\r\n    <li style=\"margin-bottom:6px;\">Promosi dan Edukasi</li>\r\n    <li style=\"margin-bottom:6px;\">Meningkatkan Aksesibilitas</li>\r\n    <li style=\"margin-bottom:6px;\">Membangun Kepercayaan Publik</li>\r\n    <li style=\"margin-bottom:6px;\">Pelestarian Nilai Sejarah</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 16px; text-align:left;\">Bentuk Kegiatan Penjangkauan Arsip</h3>\r\n\r\n  <!-- KARTU KEGIATAN - BARIS 1 -->\r\n  <div style=\"display:flex; gap:16px; margin-bottom:16px;\">\r\n\r\n    <!-- KARTU 1: Pameran Arsip -->\r\n    <div style=\"flex:1; border:1px solid #e0e0e0; border-radius:8px; padding:16px; text-align:left;\">\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;\">\r\n        <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n        <a href=\"#\" style=\"background-color:#2196f3; color:#fff; padding:7px 20px; border-radius:20px; text-decoration:none; font-size:13px; font-weight:bold;\">Visit</a>\r\n      </div>\r\n      <p style=\"font-weight:bold; margin:0 0 8px; font-size:14px;\">Pameran Arsip</p>\r\n      <ul style=\"list-style-type:disc; padding-left:18px; margin:0; font-size:13px; color:#444;\">\r\n        <li style=\"margin-bottom:4px;\">Pameran fisik di ruang publik</li>\r\n        <li style=\"margin-bottom:4px;\">Pameran tematik</li>\r\n        <li style=\"margin-bottom:4px;\">Pameran virtual berbasis digital</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <!-- KARTU 2: Publikasi dan Media -->\r\n    <div style=\"flex:1; border:1px solid #e0e0e0; border-radius:8px; padding:16px; text-align:left;\">\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;\">\r\n        <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n        <a href=\"#\" style=\"background-color:#2196f3; color:#fff; padding:7px 20px; border-radius:20px; text-decoration:none; font-size:13px; font-weight:bold;\">Visit</a>\r\n      </div>\r\n      <p style=\"font-weight:bold; margin:0 0 8px; font-size:14px;\">Publikasi dan Media</p>\r\n      <ul style=\"list-style-type:disc; padding-left:18px; margin:0; font-size:13px; color:#444;\">\r\n        <li style=\"margin-bottom:4px;\">Buku dan katalog arsip</li>\r\n        <li style=\"margin-bottom:4px;\">Artikel sejarah berbasis arsip</li>\r\n        <li style=\"margin-bottom:4px;\">Konten media sosial edukatif</li>\r\n      </ul>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <!-- KARTU KEGIATAN - BARIS 2 -->\r\n  <div style=\"display:flex; gap:16px; margin-bottom:16px;\">\r\n\r\n    <!-- KARTU 3: Platform Digital -->\r\n    <div style=\"flex:1; max-width:50%; border:1px solid #e0e0e0; border-radius:8px; padding:16px; text-align:left;\">\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;\">\r\n        <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n        <a href=\"#\" style=\"background-color:#2196f3; color:#fff; padding:7px 20px; border-radius:20px; text-decoration:none; font-size:13px; font-weight:bold;\">Visit</a>\r\n      </div>\r\n      <p style=\"font-weight:bold; margin:0 0 8px; font-size:14px;\">Platform Digital</p>\r\n      <ul style=\"list-style-type:disc; padding-left:18px; margin:0; font-size:13px; color:#444;\">\r\n        <li style=\"margin-bottom:4px;\">Website arsip</li>\r\n        <li style=\"margin-bottom:4px;\">Database arsip digital</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div style=\"flex:1;\"></div>\r\n  </div>\r\n\r\n</div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Archive outreach is a strategic effort by archival institutions to introduce, promote and bring archives closer to the wider community.</p>\r\n\r\n  <!-- QUOTE BOX -->\r\n  <div style=\"background-color:#4a4a4a; color:#ffffff; border-radius:6px; padding:16px 20px; margin:20px 0; font-style:italic; font-size:14px; line-height:1.8;\">\r\n    Based on Law Number 43 of 2009 concerning Archives, archives are the nation\'s collective memory, a source of information and material for national accountability. Therefore, archival institutions not only store archives, but also actively disseminate archival information to the public.\r\n  </div>\r\n\r\n  <p>Archive outreach was conducted for:</p>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:20px;\">\r\n    <li style=\"margin-bottom:6px;\">Raising public awareness about the importance of archives</li>\r\n    <li style=\"margin-bottom:6px;\">Expanding the use of archives as historical sources</li>\r\n    <li style=\"margin-bottom:6px;\">Supports education and research</li>\r\n    <li style=\"margin-bottom:6px;\">Building an image of archives as an open and trusted source of information</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Archive Outreach Objectives</h3>\r\n  <ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:20px;\">\r\n    <li style=\"margin-bottom:6px;\">Promotion and Education</li>\r\n    <li style=\"margin-bottom:6px;\">Improve Accessibility</li>\r\n    <li style=\"margin-bottom:6px;\">Building Public Trust</li>\r\n    <li style=\"margin-bottom:6px;\">Preservation of Historical Values</li>\r\n  </ul>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 16px; text-align:left;\">Archive Outreach Activity Form</h3>\r\n\r\n  <!-- ACTIVITY CARD - LINE 1 -->\r\n  <div style=\"display:flex; gap:16px; margin-bottom:16px;\">\r\n\r\n    <!-- CARD 1: Archive Exhibition -->\r\n    <div style=\"flex:1; border:1px solid #e0e0e0; border-radius:8px; padding:16px; text-align:left;\">\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;\">\r\n        <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n        <a href=\"#\" style=\"background-color:#2196f3; color:#fff; padding:7px 20px; border-radius:20px; text-decoration:none; font-size:13px; font-weight:bold;\">Visit</a>\r\n      </div>\r\n      <p style=\"font-weight:bold; margin:0 0 8px; font-size:14px;\">Archive Exhibition</p>\r\n      <ul style=\"list-style-type:disc; padding-left:18px; margin:0; font-size:13px; color:#444;\">\r\n        <li style=\"margin-bottom:4px;\">Physical exhibitions in public spaces</li>\r\n        <li style=\"margin-bottom:4px;\">Thematic exhibition</li>\r\n        <li style=\"margin-bottom:4px;\">Digital-based virtual exhibition</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <!-- CARD 2: Publications and Media -->\r\n    <div style=\"flex:1; border:1px solid #e0e0e0; border-radius:8px; padding:16px; text-align:left;\">\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;\">\r\n        <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n        <a href=\"#\" style=\"background-color:#2196f3; color:#fff; padding:7px 20px; border-radius:20px; text-decoration:none; font-size:13px; font-weight:bold;\">Visit</a>\r\n      </div>\r\n      <p style=\"font-weight:bold; margin:0 0 8px; font-size:14px;\">Publications and Media</p>\r\n      <ul style=\"list-style-type:disc; padding-left:18px; margin:0; font-size:13px; color:#444;\">\r\n        <li style=\"margin-bottom:4px;\">Books and archive catalogs</li>\r\n        <li style=\"margin-bottom:4px;\">Archive-based historical articles</li>\r\n        <li style=\"margin-bottom:4px;\">Educational social media content</li>\r\n      </ul>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <!-- ACTIVITY CARD - LINE 2 -->\r\n  <div style=\"display:flex; gap:16px; margin-bottom:16px;\">\r\n\r\n    <!-- CARD 3: Digital Platforms -->\r\n    <div style=\"flex:1; max-width:50%; border:1px solid #e0e0e0; border-radius:8px; padding:16px; text-align:left;\">\r\n      <div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;\">\r\n        <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n        <a href=\"#\" style=\"background-color:#2196f3; color:#fff; padding:7px 20px; border-radius:20px; text-decoration:none; font-size:13px; font-weight:bold;\">Visit</a>\r\n      </div>\r\n      <p style=\"font-weight:bold; margin:0 0 8px; font-size:14px;\">Digital Platforms</p>\r\n      <ul style=\"list-style-type:disc; padding-left:18px; margin:0; font-size:13px; color:#444;\">\r\n        <li style=\"margin-bottom:4px;\">Archive website</li>\r\n        <li style=\"margin-bottom:4px;\">Digital archive database</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div style=\"flex:1;\"></div>\r\n  </div>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-04-22 12:46:25','2026-04-28 20:02:34'),(50,'Akuisisi Arsip','Archive Acquisition','link',43,'/pengelolaan/akuisisi-arsip',7,'<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Berdasarkan Pasal 1 Undang-Undang Nomor 43 Tahun 2009 tentang Kearsipan, akuisisi arsip statis adalah proses penambahan khasanah arsip statis pada lembaga kearsipan yang dilaksanakan melalui kegiatan penyerahan arsip statis dan pengelolaan hak penguasaan atas arsip statis dari pencipta arsip kepada lembaga kearsipan.</p>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Penyerahan Arsip Statis</h3>\r\n  <p>Penyerahan arsip statis adalah proses pemindahan arsip statis dari instansi pemerintah, pemerintah daerah, organisasi politik, organisasi kemasyarakatan, lembaga pendidikan, termasuk swasta dan perseorangan yang menerima anggaran negara dan/atau bantuan luar negeri, kepada lembaga kearsipan.</p>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Prosedur Penyerahan Arsip Statis</h3>\r\n  <p>Arsip yang memiliki nilai sejarah nasional dan telah habis masa retensinya dan/atau ditetapkan permanen sesuai Jadwal Retensi Arsip dari instansi pemerintah, pemerintah daerah, organisasi politik, organisasi kemasyarakatan, dan perseorangan skala nasional.</p>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Syarat dan Ketentuan Layanan Penyerahan Arsip Statis</h3>\r\n  <p>Prosedur penyerahan arsip statis dilakukan sebagai berikut:</p>\r\n  <ol style=\"padding-left:20px; margin-bottom:20px;\">\r\n    <li style=\"margin-bottom:10px;\">Seleksi dan penyusunan daftar arsip usul serah oleh Pencipta Arsip;</li>\r\n    <li style=\"margin-bottom:10px;\">Penilaian oleh panitia penilai arsip lembaga kearsipan terhadap arsip yang diusulkan untuk diserahkan;</li>\r\n    <li style=\"margin-bottom:10px;\">Pemberitahuan penyerahan arsip statis oleh pimpinan lembaga kearsipan kepada pimpinan pencipta arsip sesuai kewenangannya, disertai pernyataan dari pimpinan pencipta arsip bahwa arsip yang akan diserahkan adalah autentik, reliabel, utuh, dan dapat digunakan;</li>\r\n    <li style=\"margin-bottom:10px;\">Verifikasi dan persetujuan oleh pimpinan lembaga kearsipan sesuai kewenangannya;</li>\r\n    <li style=\"margin-bottom:10px;\">Penetapan arsip yang akan diserahkan oleh pimpinan pencipta arsip; dan</li>\r\n    <li style=\"margin-bottom:10px;\">Pelaksanaan serah terima arsip statis oleh pimpinan pencipta arsip kepada pimpinan lembaga kearsipan, disertai berita acara serah terima dan daftar arsip yang diserahkan.</li>\r\n  </ol>\r\n\r\n  <!-- TABEL JAM -->\r\n  <table style=\"width:100%; border-collapse:collapse; font-size:14px; margin-bottom:24px;\">\r\n    <thead>\r\n      <tr>\r\n        <th style=\"background:#1a3a6b; color:#fff; padding:10px 14px; text-align:left;\">Senin – Kamis</th>\r\n        <th style=\"background:#1a3a6b; color:#fff; padding:10px 14px; text-align:left;\">Jumat</th>\r\n        <th style=\"background:#1a3a6b; color:#fff; padding:10px 14px; text-align:left;\">Sabtu – Minggu</th>\r\n      </tr>\r\n    </thead>\r\n    <tbody>\r\n      <tr>\r\n        <td style=\"padding:10px 14px; border:1px solid #e0e0e0; vertical-align:top;\">\r\n          09.00 – 15.00 WIB<br>\r\n          <span style=\"font-size:13px; color:#666;\">Istirahat: 12.00 – 13.00 WIB</span>\r\n        </td>\r\n        <td style=\"padding:10px 14px; border:1px solid #e0e0e0; vertical-align:top;\">\r\n          09.00 – 15.00 WIB<br>\r\n          <span style=\"font-size:13px; color:#666;\">Istirahat: 11.30 – 13.00 WIB</span>\r\n        </td>\r\n        <td style=\"padding:10px 14px; border:1px solid #e0e0e0; vertical-align:top; color:#888;\">\r\n          Weekend\r\n        </td>\r\n      </tr>\r\n    </tbody>\r\n  </table>\r\n\r\n  <p>Panduan Online Akuisisi Arsip dapat diakses melalui tautan berikut:</p>\r\n  <p style=\"text-align:left;\">\r\n    <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:11px 28px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n      Padaku Arsip\r\n    </a>\r\n  </p>\r\n\r\n  <hr style=\"border:none; border-top:1px solid #e0e0e0; margin:28px 0;\">\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:0 0 16px; text-align:left;\">Mekanisme Penyerahan Arsip</h3>\r\n\r\n  <!-- INFOGRAFIS 1 -->\r\n  <div style=\"border-radius:8px; overflow:hidden; margin-bottom:12px;\">\r\n    <img src=\"https://lh3.googleusercontent.com/d/1PCU-K2Suy6BK0BJb-5OUO9yiJpVXrO6E\"\r\n      style=\"width:100%; display:block;\"\r\n      alt=\"Infografis Alur Penyerahan Arsip Statis Halaman 1\">\r\n  </div>\r\n\r\n  <!-- INFOGRAFIS 2 -->\r\n  <div style=\"border-radius:8px; overflow:hidden; margin-bottom:0;\">\r\n    <img src=\"https://lh3.googleusercontent.com/d/1-l_6tHscA7gCQCZ8LdSep_ENhbVAXb7J\"\r\n      style=\"width:100%; display:block;\"\r\n      alt=\"Infografis Alur Penyerahan Arsip Statis Halaman 2\">\r\n  </div>\r\n\r\n<!-- KOTAK UNDUH PDF -->\r\n  <div style=\"border:1px solid #e0e0e0; border-top:none; border-radius:0 0 8px 8px; padding:24px; text-align:center; background:#ffffff; box-shadow:0 6px 16px rgba(0,0,0,0.12); margin-bottom:40px;\">\r\n    <a href=\"https://drive.google.com/file/d/1-uyV5hiycUebV7fHtfosdSwlWBx4xxt0/view?usp=sharing\" target=\"_blank\"\r\n      style=\"display:inline-flex; align-items:center; gap:8px; background-color:#1a3a6b; color:#ffffff; padding:12px 36px; border-radius:30px; text-decoration:none; font-weight:bold; font-size:15px; box-shadow:0 4px 10px rgba(26,58,107,0.4);\">\r\n      ⬇ Unduh PDF\r\n    </a>\r\n  </div>','<div style=\"max-width:680px; font-family:sans-serif; color:#222; line-height:1.8; text-align:justify;\">\r\n\r\n  <p>Based on Article 1 of Law Number 43 of 2009 concerning Archives, acquisition of static archives is the process of adding to the repertoire of static archives at an archival institution which is carried out through the activity of handing over static archives and managing control rights over static archives from the creator of the archive to the archival institution.</p>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Static Archive Submission</h3>\r\n  <p>Delivery of static archives is the process of transferring static archives from government agencies, regional governments, political organizations, community organizations, educational institutions, including private companies and individuals who receive the state budget and/or foreign aid, to archival institutions.</p>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Static Archive Submission Procedure</h3>\r\n  <p>Archives that have national historical value and whose retention period has expired and/or been designated as permanent according to the Archives Retention Schedule from government agencies, regional governments, political organizations, community organizations and individuals on a national scale.</p>\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:24px 0 10px; text-align:left;\">Static Archive Submission Service Terms and Conditions</h3>\r\n  <p>The procedure for submitting static archives is as follows:</p>\r\n  <ol style=\"padding-left:20px; margin-bottom:20px;\">\r\n    <li style=\"margin-bottom:10px;\">Selection and preparation of a list of archives proposed for handover by the Archives Creator;</li>\r\n    <li style=\"margin-bottom:10px;\">Assessment by the archives assessment committee of the archival institution of the archives proposed for submission;</li>\r\n    <li style=\"margin-bottom:10px;\">Notification of handover of static archives by the head of the archival institution to the head of the archive creator in accordance with his/her authority, accompanied by a statement from the head of the archive creator that the archives to be handed over are authentic, reliable, intact and usable;</li>\r\n    <li style=\"margin-bottom:10px;\">Verification and approval by the head of the archival institution in accordance with their authority;</li>\r\n    <li style=\"margin-bottom:10px;\">Determination of archives to be submitted by the chief archive creator; and</li>\r\n    <li style=\"margin-bottom:10px;\">The handover of static archives by the head of the archive creator to the head of the archival institution, accompanied by a handover report and a list of archives handed over.</li>\r\n  </ol>\r\n\r\n  <!-- CLOCK TABLE -->\r\n  <table style=\"width:100%; border-collapse:collapse; font-size:14px; margin-bottom:24px;\">\r\n    <head>\r\n      <tr>\r\n        <th style=\"background:#1a3a6b; color:#fff; padding:10px 14px; text-align:left;\">Monday – Thursday</th>\r\n        <th style=\"background:#1a3a6b; color:#fff; padding:10px 14px; text-align:left;\">Friday</th>\r\n        <th style=\"background:#1a3a6b; color:#fff; padding:10px 14px; text-align:left;\">Saturday – Sunday</th>\r\n      </tr>\r\n    </head>\r\n    <tbody>\r\n      <tr>\r\n        <td style=\"padding:10px 14px; border:1px solid #e0e0e0; vertical-align:top;\">\r\n          09.00 – 15.00 WIB<br>\r\n          <span style=\"font-size:13px; color:#666;\">Break: 12.00 – 13.00 WIB</span>\r\n        </td>\r\n        <td style=\"padding:10px 14px; border:1px solid #e0e0e0; vertical-align:top;\">\r\n          09.00 – 15.00 WIB<br>\r\n          <span style=\"font-size:13px; color:#666;\">Break: 11.30 – 13.00 WIB</span>\r\n        </td>\r\n        <td style=\"padding:10px 14px; border:1px solid #e0e0e0; vertical-align:top; color:#888;\">\r\n          Weekends\r\n        </td>\r\n      </tr>\r\n    </tbody>\r\n  </table>\r\n\r\n  <p>The Archive Acquisition Online Guide can be accessed via the following link:</p>\r\n  <p style=\"text-align:left;\">\r\n    <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:11px 28px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n      Me Archives\r\n    </a>\r\n  </p>\r\n\r\n  <hr style=\"border:none; border-top:1px solid #e0e0e0; margin:28px 0;\">\r\n\r\n  <h3 style=\"font-size:17px; font-weight:bold; margin:0 0 16px; text-align:left;\">Archive Submission Mechanism</h3>\r\n\r\n  <!-- INFOGRAPHIC 1 -->\r\n  <div style=\"border-radius:8px; overflow:hidden; margin-bottom:12px;\">\r\n    <img src=\"https://lh3.googleusercontent.com/d/1PCU-K2Suy6BK0BJb-5OUO9yiJpVXrO6E\"\r\n      style=\"width:100%; display:block;\"\r\n      alt=\"Static Archive Submission Flow Infographic Page 1\">\r\n  </div>\r\n\r\n  <!-- INFOGRAPHIC 2 -->\r\n  <div style=\"border-radius:8px; overflow:hidden; margin-bottom:0;\">\r\n    <img src=\"https://lh3.googleusercontent.com/d/1-l_6tHscA7gCQCZ8LdSep_ENhbVAXb7J\"\r\n      style=\"width:100%; display:block;\"\r\n      alt=\"Static Archive Submission Flow Infographic Page 2\">\r\n  </div>\r\n\r\n<!-- PDF DOWNLOAD BOX -->\r\n  <div style=\"border:1px solid #e0e0e0; border-top:none; border-radius:0 0 8px 8px; padding:24px; text-align:center; background:#ffffff; box-shadow:0 6px 16px rgba(0,0,0,0.12); margin-bottom:40px;\">\r\n    <a href=\"https://drive.google.com/file/d/1-uyV5hiycUebV7fHtfosdSwlWBx4xxt0/view?usp=sharing\" target=\"_blank\"\r\n      style=\"display:inline-flex; align-items:center; gap:8px; background-color:#1a3a6b; color:#ffffff; padding:12px 36px; border-radius:30px; text-decoration:none; font-weight:bold; font-size:15px; box-shadow:0 4px 10px rgba(26,58,107,0.4);\">\r\n      ⬇ Download PDF\r\n    </a>\r\n  </div>',0,'none','none',NULL,NULL,'2026-04-22 12:47:00','2026-04-28 21:34:36'),(51,'Perpustakaan','Library','link',5,'/layanan-publik/perpustakaan',6,'<div style=\"max-width:680px; text-align:justify;\">\r\n\r\n<p>Layanan Perpustakaan DABB menyediakan bahan pustaka dan referensi untuk mendukung kegiatan kearsipan dan penelitian. Layanan ini memberikan akses kepada pengguna untuk membaca, menelusuri, dan memanfaatkan koleksi yang tersedia sesuai dengan peraturan yang berlaku.</p>\r\n\r\n<h3 style=\"text-align:left;\">Tujuan</h3>\r\n<ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n  <li style=\"margin-bottom:6px;\">Memberikan akses informasi terkait arsip dan sejarah.</li>\r\n  <li style=\"margin-bottom:6px;\">Mendukung kegiatan penelitian dan penulisan ilmiah.</li>\r\n  <li style=\"margin-bottom:6px;\">Menjadi sumber referensi dalam pengelolaan dan pelestarian arsip.</li>\r\n</ul>\r\n\r\n<p style=\"margin-top:24px; text-align:left;\">\r\n  <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:12px 28px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n    Kunjungi Website Perpustakaan\r\n  </a>\r\n</p>\r\n\r\n<hr style=\"border:none; border-top:1px solid #e0e0e0; margin:28px 0;\">\r\n\r\n<table style=\"width:100%; border-collapse:collapse;\">\r\n  <tr>\r\n    <td style=\"padding:12px 16px; vertical-align:top; width:56px;\">\r\n      <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n    </td>\r\n    <td style=\"padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;\">\r\n      <strong>Peminjaman Buku</strong><br>\r\n      <span style=\"color:#555555; font-size:14px;\">Lorem Ipsum</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 16px; vertical-align:top; width:56px;\">\r\n      <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n    </td>\r\n    <td style=\"padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;\">\r\n      <strong>Koleksi Digital</strong><br>\r\n      <span style=\"color:#555555; font-size:14px;\">Akses e-book, jurnal ilmiah, dan artikel kapan saja dan di mana saja.</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 16px; vertical-align:top; width:56px;\">\r\n      <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n    </td>\r\n    <td style=\"padding:12px 0; vertical-align:top;\">\r\n      <strong>Ruang Baca dan Belajar</strong><br>\r\n      <span style=\"color:#555555; font-size:14px;\">Ruangan ber-AC yang nyaman dengan WiFi gratis, dilengkapi kursi dan meja untuk belajar individu maupun kelompok.</span>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<hr style=\"border:none; border-top:1px solid #e0e0e0; margin:28px 0;\">\r\n\r\n<h3 style=\"text-align:left;\">Jam Layanan</h3>\r\n<table style=\"border-collapse:collapse; width:100%; font-size:14px; text-align:left;\">\r\n  <tr>\r\n    <td style=\"padding:5px 0; width:220px;\">Senin – Jumat</td>\r\n    <td style=\"padding:5px 8px; width:16px;\">:</td>\r\n    <td style=\"padding:5px 0;\">09.00 – 15.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:5px 0;\">Istirahat (Senin – Kamis)</td>\r\n    <td style=\"padding:5px 8px;\">:</td>\r\n    <td style=\"padding:5px 0;\">12.00 – 13.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:5px 0;\">(Jumat)</td>\r\n    <td style=\"padding:5px 8px;\">:</td>\r\n    <td style=\"padding:5px 0;\">11.30 – 13.00 WIB</td>\r\n  </tr>\r\n</table>\r\n\r\n<h3 style=\"text-align:left;\">Tata Tertib</h3>\r\n<ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n  <li style=\"margin-bottom:6px;\">Dilarang membawa makanan dan minuman</li>\r\n  <li style=\"margin-bottom:6px;\">Dilarang merusak buku atau arsip</li>\r\n  <li style=\"margin-bottom:6px;\">Harap menjaga ketenangan</li>\r\n</ul>\r\n\r\n<div style=\"display:flex; gap:2%; margin:20px 0;\">\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Foto 1</div>\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Foto 2</div>\r\n</div>\r\n\r\n<p style=\"margin-top:20px; text-align:left;\">\r\n  <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:10px 22px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n    ⬇ Unduh PDF\r\n  </a>\r\n</p>\r\n\r\n</div>','<div style=\"max-width:680px; text-align:justify;\">\r\n\r\n<p>DABB Library Services provides library and reference materials to support archival and research activities. This service provides users with access to read, browse and utilize available collections in accordance with applicable regulations.</p>\r\n\r\n<h3 style=\"text-align:left;\">Destination</h3>\r\n<ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n  <li style=\"margin-bottom:6px;\">Provides access to information related to archives and history.</li>\r\n  <li style=\"margin-bottom:6px;\">Supports scientific research and writing activities.</li>\r\n  <li style=\"margin-bottom:6px;\">Become a reference source in archival management and preservation.</li>\r\n</ul>\r\n\r\n<p style=\"margin-top:24px; text-align:left;\">\r\n  <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:12px 28px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n    Visit the Library Website\r\n  </a>\r\n</p>\r\n\r\n<hr style=\"border:none; border-top:1px solid #e0e0e0; margin:28px 0;\">\r\n\r\n<table style=\"width:100%; border-collapse:collapse;\">\r\n  <tr>\r\n    <td style=\"padding:12px 16px; vertical-align:top; width:56px;\">\r\n      <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n    </td>\r\n    <td style=\"padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;\">\r\n      <strong>Book Lending</strong><br>\r\n      <span style=\"color:#555555; font-size:14px;\">Lorem Ipsum</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 16px; vertical-align:top; width:56px;\">\r\n      <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n    </td>\r\n    <td style=\"padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;\">\r\n      <strong>Digital Collection</strong><br>\r\n      <span style=\"color:#555555; font-size:14px;\">Access e-books, scientific journals and articles anytime and anywhere.</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 16px; vertical-align:top; width:56px;\">\r\n      <div style=\"width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;\"></div>\r\n    </td>\r\n    <td style=\"padding:12px 0; vertical-align:top;\">\r\n      <strong>Reading and Study Room</strong><br>\r\n      <span style=\"color:#555555; font-size:14px;\">Comfortable air-conditioned room with free WiFi, equipped with chairs and tables for individual and group study.</span>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<hr style=\"border:none; border-top:1px solid #e0e0e0; margin:28px 0;\">\r\n\r\n<h3 style=\"text-align:left;\">Service Hours</h3>\r\n<table style=\"border-collapse:collapse; width:100%; font-size:14px; text-align:left;\">\r\n  <tr>\r\n    <td style=\"padding:5px 0; width:220px;\">Monday – Friday</td>\r\n    <td style=\"padding:5px 8px; width:16px;\">:</td>\r\n    <td style=\"padding:5px 0;\">09.00 – 15.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:5px 0;\">Break (Monday – Thursday)</td>\r\n    <td style=\"padding:5px 8px;\">:</td>\r\n    <td style=\"padding:5px 0;\">12.00 – 13.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:5px 0;\">(Friday)</td>\r\n    <td style=\"padding:5px 8px;\">:</td>\r\n    <td style=\"padding:5px 0;\">11.30 – 13.00 WIB</td>\r\n  </tr>\r\n</table>\r\n\r\n<h3 style=\"text-align:left;\">Rules</h3>\r\n<ul style=\"list-style-type:disc; padding-left:20px; margin-bottom:24px;\">\r\n  <li style=\"margin-bottom:6px;\">Bringing food and drinks is prohibited</li>\r\n  <li style=\"margin-bottom:6px;\">Do not damage books or archives</li>\r\n  <li style=\"margin-bottom:6px;\">Please maintain calm</li>\r\n</ul>\r\n\r\n<div style=\"display:flex; gap:2%; margin:20px 0;\">\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Photo 1</div>\r\n  <div style=\"width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;\">Photo 2</div>\r\n</div>\r\n\r\n<p style=\"margin-top:20px; text-align:left;\">\r\n  <a href=\"#\" style=\"display:inline-block; background-color:#1565c0; color:#ffffff; padding:10px 22px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;\">\r\n    ⬇ Download PDF\r\n  </a>\r\n</p>\r\n\r\n</div>',0,'none','none',NULL,NULL,'2026-04-26 13:58:52','2026-04-28 18:24:38');
